You are generating Go code. Only generate the required function. DO NOT generate main function.
The reference solution of that problem in Javascript is 
function solve(nums, k) {
    let total_sum = 0;
    let current_S = 0;
    let prev_dp = 0;
    let mod_map = new Map();
    mod_map.set(0, 0);

    for (let i = 0; i < nums.length; i++) {
        current_S += nums[i];
        const current_mod = current_S % k;
        let candidate = mod_map.get(current_mod) !== undefined ? mod_map.get(current_mod) + current_S : -Infinity;
        const current_dp = Math.max(prev_dp, candidate);

        const valueToStore = current_dp - current_S;
        if (mod_map.has(current_mod)) {
            if (valueToStore > mod_map.get(current_mod)) {
                mod_map.set(current_mod, valueToStore);
            }
        } else {
            mod_map.set(current_mod, valueToStore);
        }

        prev_dp = current_dp;
    }

    return current_S - prev_dp;
}

